class Grupp:
  def __init__ (self, namn, medlemmarna):
    self.gruppnamn = namn
    self.medlemmar = medlemmarna

  def __str__ (self):
    sträng = self.gruppnamn + " har följande medlemmar: " 
    for medlem in self.medlemmar:
        sträng += str(medlem +  ", ")
    return sträng[0:-2]

  def lägg_till_medlem(self, ny_medlem):
    self.medlemmar.append(ny_medlem)

  def ta_bort_medlem(self, medlem):
    if medlem in self.medlemmar:
      self.medlemmar.remove(medlem)
      print(medlem, "är borttagen")
    else:
      print("Medlemen finns inte gruppen. ")

  def ordförande(self):
    if len(self.medlemmar) == 0:
      print("Finns inga medlemmar i grupp", self.gruppnamn)
      return None
    ordförande = self.medlemmar[0]
    for i in range(len(self.medlemmar)):
      if len(ordförande) < len(self.medlemmar[i]):
        ordförande = self.medlemmar[i]
    return ordförande

def läsa_in_från_fil():
  try:
    fil = open("grupper.txt", "r")
    rad = fil.readline().strip()
  except FileNotFoundError:
    print("Ingen fil med namnet grupper.txt hittades.")
    rad = ""
  grupper = []
  while rad != "":           #Så länge som raden inte är tom
    rad = rad.split()        #delar upp strängen i två
    grupp = Grupp(rad[0], rad[1:])
    grupper.append(grupp)
    rad = fil.readline().strip()  #läser in nästa rad
  return grupper

def skriv_till_fil(grupper):
  """Sparar grupperna och dess medlemmar till fil
  Inparameter: grupper, lista med Grupp-objekt)
  Returerar:  inget"""
  fil = open("grupper.txt", "w")
  for objekt in grupper:
    fil.write(objekt.gruppnamn + " ")
    for element in objekt.medlemmar:
      fil.write(str(element) + " ")
    fil.write("\n")
  fil.close() 

def välj_grupp(grupper):
  grupp_namn = input("Vad heter gruppen? ")
  for grupp in grupper:
    if grupp_namn == grupp.gruppnamn:
      return grupp
  print("Gruppen hittades inte.")

def undermeny(grupp):
  while True:
    print("Undermeny\n1. Lägga till en medlem\n2. Ta bort en medlem\n3. Gå tillbaka till huvudmenyn")
    val = input("Vad vill du göra? ")
    if val == "1":
      medlem = input("Vad heter den nya medlemmen? ")
      grupp.lägg_till_medlem(medlem)
    elif val == "2":
      medlem = input("Vad heter medlemmen du vill ta bort? ")
      grupp.ta_bort_medlem(medlem)
    elif val == "3":
      break
    else: 
      print("Inte ett riktigt val! Välj 1-3")

def meny(grupper):
  while True:
    print("Huvudmeny \n1. Visa alla grupper.\n2. Ändra en grupp\n3. Skriva ut ordförande i varje grupp\n4. Avsluta")
    val = input("Vad väljer du? ")
    if val == "1":
      for grupp in grupper:
        print(grupp)
    elif val == "2":
      grupp = välj_grupp(grupper)
      if grupp != None:
        undermeny(grupp)
    elif val == "3":
      for grupp in grupper:
        if grupp.ordförande() != None:
          print("Ordförande är", grupp.ordförande())
    elif val == "4":
      print("Programmet avslutas")
      skriv_till_fil(grupper)
      break
    else:
      print("Inte ett riktigt val!")

def huvudprogram():
  alla_grupper = läsa_in_från_fil()
  meny(alla_grupper)

huvudprogram()
